class Solution {
public:
    vector<string> removeInvalidParentheses(string s) {
        vector<string> result;
        int countLeft = 0, countRight = 0;
        for (char c : s) {
            if (c == '(') countLeft++;
            else if (c == ')') {
                if (countLeft > 0) countLeft--;
                else countRight++;
            }
        }
        dfs(s, 0, countLeft, countRight, result);
        return result;
    }

    void dfs(string s, int start, int leftRem, int rightRem, vector<string>& result) {
        if (leftRem == 0 && rightRem == 0) {
            if (isValid(s)) {
                result.push_back(s);
            }
            return;
        }
        for (int i = start; i < s.size(); i++) {
            if (i > start && s[i] == s[i-1]) continue;
            if (s[i] == '(' && leftRem > 0) {
                dfs(s.substr(0, i) + s.substr(i+1), i, leftRem-1, rightRem, result);
            }
            if (s[i] == ')' && rightRem > 0) {
                dfs(s.substr(0, i) + s.substr(i+1), i, leftRem, rightRem-1, result);
            }
        }
    }

    bool isValid(string s) {
        int count = 0;
        for (char c : s) {
            if (c == '(') count++;
            else if (c == ')') {
                count--;
                if (count < 0) return false;
            }
        }
        return count == 0;
    }
};
